-- =====================================================
-- GRANTS
-- =====================================================

GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE "public"."user_attributes" TO "authenticated";
GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE "public"."role_attributes" TO "authenticated";
GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE "public"."permission_conditions" TO "authenticated";
GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE "public"."attribute_definitions" TO "authenticated";

GRANT ALL ON TABLE "public"."user_attributes" TO "service_role";
GRANT ALL ON TABLE "public"."role_attributes" TO "service_role";
GRANT ALL ON TABLE "public"."permission_conditions" TO "service_role";
GRANT ALL ON TABLE "public"."attribute_definitions" TO "service_role";

-- =====================================================
-- RLS POLICIES
-- =====================================================

-- User Attributes: Eigene lesen, Admins alles
DROP POLICY IF EXISTS "User attributes read own" ON "public"."user_attributes";
CREATE POLICY "User attributes read own" ON "public"."user_attributes"
    FOR SELECT TO authenticated
    USING (
        public.is_admin() 
        OR sales_id = public.get_current_sales_id()
    );

DROP POLICY IF EXISTS "User attributes write admin" ON "public"."user_attributes";
CREATE POLICY "User attributes write admin" ON "public"."user_attributes"
    FOR ALL TO authenticated
    USING (public.is_admin())
    WITH CHECK (public.is_admin());

-- Role Attributes: Lesen für alle, Schreiben für Admins
DROP POLICY IF EXISTS "Role attributes read" ON "public"."role_attributes";
CREATE POLICY "Role attributes read" ON "public"."role_attributes"
    FOR SELECT TO authenticated USING (true);

DROP POLICY IF EXISTS "Role attributes write admin" ON "public"."role_attributes";
CREATE POLICY "Role attributes write admin" ON "public"."role_attributes"
    FOR ALL TO authenticated
    USING (public.is_admin())
    WITH CHECK (public.is_admin());

-- Permission Conditions: Lesen für alle, Schreiben für Admins
DROP POLICY IF EXISTS "Permission conditions read" ON "public"."permission_conditions";
CREATE POLICY "Permission conditions read" ON "public"."permission_conditions"
    FOR SELECT TO authenticated USING (true);

DROP POLICY IF EXISTS "Permission conditions write admin" ON "public"."permission_conditions";
CREATE POLICY "Permission conditions write admin" ON "public"."permission_conditions"
    FOR ALL TO authenticated
    USING (public.is_admin())
    WITH CHECK (public.is_admin());

-- Attribute Definitions: Lesen für alle, Schreiben für Admins
DROP POLICY IF EXISTS "Attribute definitions read" ON "public"."attribute_definitions";
CREATE POLICY "Attribute definitions read" ON "public"."attribute_definitions"
    FOR SELECT TO authenticated USING (true);

DROP POLICY IF EXISTS "Attribute definitions write admin" ON "public"."attribute_definitions";
CREATE POLICY "Attribute definitions write admin" ON "public"."attribute_definitions"
    FOR ALL TO authenticated
    USING (public.is_admin())
    WITH CHECK (public.is_admin());

-- =====================================================
-- VIEW FÜR BENUTZER MIT ATTRIBUTEN
-- =====================================================

DROP VIEW IF EXISTS "public"."user_with_attributes";
CREATE VIEW "public"."user_with_attributes"
WITH (security_invoker=on)
AS
SELECT 
    s.id as sales_id,
    s.first_name,
    s.last_name,
    s.email,
    s.administrator,
    r.id as role_id,
    r.name as role_name,
    COALESCE(
        (SELECT jsonb_object_agg(ua.attribute_name, ua.attribute_value)
         FROM public.user_attributes ua 
         WHERE ua.sales_id = s.id),
        '{}'::jsonb
    ) as user_attributes,
    COALESCE(
        (SELECT jsonb_object_agg(ra.attribute_name, 
            (SELECT jsonb_agg(ra2.attribute_value) 
             FROM public.role_attributes ra2 
             WHERE ra2.role_id = r.id AND ra2.attribute_name = ra.attribute_name))
         FROM public.role_attributes ra 
         WHERE ra.role_id = r.id
         GROUP BY ra.role_id),
        '{}'::jsonb
    ) as role_attributes
FROM public.sales s
LEFT JOIN public.roles r ON s.role_id = r.id;

GRANT SELECT ON "public"."user_with_attributes" TO "authenticated";
